import{_ as d,o as a,c as e,a5 as o}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"Module 0 — Dev & sysadmin fundamentals","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/index.md","filePath":"module-0/index.md","lastUpdated":1780937944000}'),r={name:"module-0/index.md"};function s(l,t,n,i,u,m){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="module-0-—-dev-sysadmin-fundamentals" tabindex="-1">Module 0 — Dev &amp; sysadmin fundamentals <a class="header-anchor" href="#module-0-—-dev-sysadmin-fundamentals" aria-label="Permalink to &quot;Module 0 — Dev &amp; sysadmin fundamentals&quot;">​</a></h1><blockquote><p><strong>TL;DR.</strong> Solana validator operations це <strong>80% sysadmin/dev fundamentals + 20% Solana-specific</strong>. Цей модуль — fundamentals: як з source code робиться binary, як git трекає зміни, як cargo білдить Rust код, як Linux запускає daemons, як shell виконує команди, як SSH передає тебе на сервер. Без цього validator ops — magic incantations. З цим — ти розумієш <strong>чому</strong> кожна команда у твоєму cheatsheet виглядає саме так.</p></blockquote><blockquote><p><strong>Як читати цей модуль.</strong> Це <strong>довідник</strong>, не лінійний курс. Можна читати послідовно, можна стрибати у потрібну секцію. Якщо при роботі з пізнішими модулями зустрінеш термін з Module 0 — повернись сюди. У <a href="/glossary">глосарії</a> кожен термін має посилання на секцію.</p></blockquote><h2 id="секціі" tabindex="-1">Секції <a class="header-anchor" href="#секціі" aria-label="Permalink to &quot;Секції&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Тема</th><th>Час</th><th>Status</th></tr></thead><tbody><tr><td>1</td><td><a href="/module-0/1-build">Build process</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>2</td><td><a href="/module-0/2-git">Git</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>3</td><td><a href="/module-0/3-cargo">Cargo / Rust</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>4</td><td><a href="/module-0/4-processes">Linux processes &amp; daemons</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>5</td><td><a href="/module-0/5-filesystem">Filesystem &amp; permissions</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>6</td><td><a href="/module-0/6-shell">Shell mechanics</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>7</td><td><a href="/module-0/7-tmux">tmux</a></td><td>15-20 хв</td><td>✅</td></tr><tr><td>8</td><td><a href="/module-0/8-ssh">SSH</a></td><td>25-35 хв</td><td>✅</td></tr><tr><td>⭐</td><td><a href="/module-0/final-quiz">Final quiz</a></td><td>30 хв</td><td>✅</td></tr></tbody></table><p><strong>Загальний час Module 0: 4-5 годин концентрованого вивчення.</strong></p><h2 id="як-проходити" tabindex="-1">Як проходити <a class="header-anchor" href="#як-проходити" aria-label="Permalink to &quot;Як проходити&quot;">​</a></h2><ol><li>Читай секцію (30-40 хв)</li><li>Запусти hands-on exercises на твоєму сервері (read-only)</li><li>Пройди mini-quiz у кінці секції (2-3 питання)</li><li>Через 5-10 хв перерви — наступна секція</li><li>У кінці модуля — final quiz (15 питань, ~30 хв)</li></ol><p>Якщо final quiz &lt;80% — повернись у секції з найбільшими прорахунками.</p>',9)])])}const f=d(r,[["render",s]]);export{c as __pageData,f as default};
